async function fetchProducts() {
  try {
    const { data } = await api.get('/products');
    return { data, error: null };
  } catch (err) {
    if (err.code === 'ECONNABORTED') {
      return { data: null, error: 'Timeout : le serveur ne répond pas' };
    }
    if (err.message === 'Network Error') {
      return { data: null, error: 'Vérifiez votre connexion internet' };
    }
    if (err.response) {
      return { data: null, error: err.response.data?.message || `Erreur ${err.response.status}` };
    }
    return { data: null, error: 'Une erreur inattendue est survenue' };
  }
}
